import { setCompodocJson } from '@storybook/addon-docs/angular';
import docJson from '../src/components/documentation.json';
setCompodocJson(docJson);
const preview = {
    parameters: {
        controls: {
            matchers: {
                color: /(background|color)$/i,
                date: /Date$/i
            }
        },
        actions: { argTypesRegex: '^on.*' },
        docs: {
            toc: {
                headingSelector: 'h1, h3',
                title: 'Table of Contents'
            },
            source: {
                transform: async (code, context) => {
                    let result = code;
                    for (const [key, value] of Object.entries(context['allArgs'])) {
                        result = result
                            .replaceAll(`"${key}"`, `"${value}"`)
                            .replaceAll(`[${key}]`, (substring) => {
                            if (!substring.startsWith('[attr.')) {
                                return key;
                            }
                            return substring;
                        })
                            .replaceAll(`this['${key}']`, `'${value}'`);
                    }
                    return result;
                }
            }
        }
    }
};
export default preview;
